model.Airbnb_bq_proj.dim_hosts_cleansed.rawCode:
{{ config(
    materialized='view'
) }}

with src_hosts as(
    select * from {{ ref('src_hosts') }}
)
select
    host_id,
    ifnull(host_name, 'Anonymous') as host_name,
    is_superhost,
    created_at,
    updated_at
from src_hosts

model.Airbnb_bq_proj.fct_reviews.rawCode:
{{
    config(
        materialized='incremental',
        on_schema_change='fail'
    )
}}

with src_reviews as(
    select * from {{ ref('src_reviews') }}
)

select
{{ dbt_utils.generate_surrogate_key(['listing_id', 'review_date', 'reviewer_name', 'review_comments']) }}
as review_id,
* from src_reviews
where review_comments is not null

{% if is_incremental() %}
    AND review_date > (select max(review_date) from {{ this }})
{% endif %}
